#define LIMIT -999

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

int maximum(int a, int b, int c) {
    int k;
    if (a <= b)
        k = b;
    else
        k = a;

    if (k <= c)
        return c;
    else
        return k;
}

kernel void nw_kernel1(global int* referrence, global int* input_itemsets, global int* output_itemsets,
                       local int* input_itemsets_l, local int* reference_l,
                       int max_cols, int penalty, int blk, int block_width, int worksize, int offset_r, int offset_c) {
    int b_index_x = get_global_id(0) / BLOCK_SIZE;

    if (b_index_x >= blk) return;

    int b_index_y = blk - 1 - b_index_x;

    int global_i = b_index_y * BLOCK_SIZE + get_global_id(0) % BLOCK_SIZE;
    int global_j = b_index_x * BLOCK_SIZE + get_global_id(0) % BLOCK_SIZE;

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            int ref_idx = max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1;
            reference_l[i * BLOCK_SIZE + j] = referrence[ref_idx];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            int inp_idx = max_cols * (b_index_y * BLOCK_SIZE + i) + b_index_x * BLOCK_SIZE + j;
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = input_itemsets[inp_idx];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            int diag = input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1];
            int left = input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty;
            int up = input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty;
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(diag, left, up);
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            int out_idx = max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1;
            input_itemsets[out_idx] = input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

kernel void nw_kernel2(global int* referrence, global int* input_itemsets, global int* output_itemsets,
                       local int* input_itemsets_l, local int* reference_l,
